mapper.select:
SELECT TWP.WORK_TYPE_CODE, TWP.WORK_TYPE_NAME, TWP.PLAN_NO, TWP.CUSTOMER_NAME, TWP.SHIP_NAME, TWP.CARGO_NAME, TWPI.DRIVER, WRP.TRUCK_PLATE, WRP.ID_NUMBER, WRP.NOTE_ID, WRP.IS_FINISHED, TWPI.TEL, CASE WHEN WRP.IS_TALLY = 1 THEN '已确认' ELSE '未确认' END IS_TALLY FROM T_WEIGHT_PLAN TWP LEFT JOIN WFG_PORTMIS_POUND.WEIGHT_RECORD_POUND WRP ON WRP.PLAN_NO = TWP.PLAN_NO LEFT JOIN T_WEIGHT_PLAN_ITEM TWPI ON (TWP.ID = TWPI.PARENT_ID and WRP.TRUCK_PLATE = TWPI.TRUCK_NO and WRP.ID_NUMBER =TWPI.ID_NUMBER and TWPI.STATUS = '0' ) WHERE TWP.STATUS = 0 AND WRP.IS_FINISHED = 0
and WRP.TRUCK_PLATE like #{truckPlateLike}
order by WEIGH_IN_DT ASC
